var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"라이트닝──! 익스큐션──!!","JPN":"ライトニング───！　エクスキューージョン！！","ENG":"Lightning ──! Execution ──!","TWN":"雷光──！處刑──！！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"흐음. 3종 침식체가 있다는 건 조금 의외였어.","JPN":"はは、第3種侵食体がいるのは予想外だったな。","ENG":"Hmpf, I didn’t expect to see a Category 3 C.O. here.","TWN":"嗯，有3類侵蝕體確實是有點意外。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"자, 어때? 메이슨 씨?","JPN":"どうだ、メイソンさん？","ENG":"What do you say, Mr. Mason?","TWN":"不過梅森，如何？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이렇게 짜릿한 볼거리까지 챙겨 주는 의뢰인은 자주 보기 힘들지 않나?","JPN":"こんなピリッとする見どころまで用意してくれる依頼主はそうそういないだろ？","ENG":"Your client does not just pay you well, but gives you an electrifying show as well!","TWN":"很少有像我這種委託人吧？可以讓你在一旁看熱鬧。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……맨주먹만으로 저 많은 침식체를 혼자 쓸어 버리다니, 정말 괴물이 따로 없군.","JPN":"……素手であのおびただしい数の侵食体を一掃するとは、\\nどっちが化け物なんだか。","ENG":"You wiped out all those C.O.s with your bare hands. You really are a monster.","TWN":"……竟然可以一個人赤手空拳打倒那麼多侵蝕體，根本是怪物吧？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"몇 번을 봐도 네가 같은 사람이란 게 믿기지가 않아.","JPN":"何度見ても、あんたが俺と同じ人間ってのが信じられないな。","ENG":"Every time I see you, I have trouble believing that you’re a human just like me.","TWN":"每次看到都覺得，平平都是人怎麼差這麼多？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"나도 한때는 그렇게 생각했지만……","JPN":"俺も一時はそう思っていたが……","ENG":"I used to think like that...","TWN":"我也曾經這麼想過……"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그런 말이 어울릴 상대는 따로 있지. 안 그런가?","JPN":"その言葉にピッタリな奴は他にいるだろ？","ENG":"But now I know that such sentiments should be directed towards someone else. Don’t you agree?","TWN":"不過應該有人比我更像怪物吧？你說是不是？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……리플레이서 퀸 말이군.","JPN":"……リプレイサー・クイーンのことか。","ENG":"You mean the Replacer Queen.","TWN":"……你是說克隆·女皇嗎？"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"확실히 상식을 벗어난 힘이었어.","JPN":"たしかに常識外れな力だった。","ENG":"She was indeed extraordinary.","TWN":"確實是超出認知範圍的能力。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그리고 그 여자를 박살내버린 코핀 컴퍼니의 소대장도……","JPN":"そして、あの女を撃破したコフィンカンパニーの小隊長も……","ENG":"And so was the Commander from the Coffin Company who crushed her.","TWN":"更誇張的是那個把她打爆的科芬公司小隊長……"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그보다 CSE 레벨은 좀 어때?","JPN":"それよりCSEレベルはどうだ？","ENG":"How’s the CSE Level now?","TWN":"CSE等級現在如何？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"틀렸어. 여전히 상승세야.","JPN":"ダメだな、依然として上昇し続けている。","ENG":"No good. It’s still rising.","TWN":"糟糕，還在持續上升中！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"음? 침식체가 사라지면 상승세는 멈추는 거 아니었나?","JPN":"うん？　侵食体が消えれば上昇も止まるんじゃなかったか？","ENG":"Huh? I thought getting rid of the C.O.s would lower the level.","TWN":"怎麼會？侵蝕體消失後，照理說等級應該會下降才對？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"다른 이유가 있다는 뜻이겠지.","JPN":"別の要因があるということだろう。","ENG":"Which means there must be some other reason for this phenomenon.","TWN":"一定是有原因的囉！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"어디에 다른 3종 침식체라도 들어앉아 있다거나, 제프티 바이오테크처럼 아티팩트 때문이라거나…….","JPN":"どこかに別の第3種侵食体が潜んでいるか、\\nそれともジェフティ・バイオテックのようにアーティファクトの影響か……","ENG":"There might be another Category 3 around here, or an Artifact, like in the Jehuty Biotech case...","TWN":"可能是其他地方也有3類侵蝕體，或是像傑夫堤生物科技一樣，是因為人造神器……"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"고심도 좌표에서 침식지대로 긴급 부상하는 바람에 침식파가 유입됐던 사례도 있긴 해.","JPN":"高深度座標から侵食地帯に緊急浮上した影響で、侵食波が流入した事例もある。","ENG":"Also, there was a case where a rapid jump from the hyper depth into a Corrupted Area brought the Corruption Rays along with them.","TWN":"又或者是從高深度座標緊急躍入侵蝕地區，導致侵蝕波滲入，這也不是沒發生過。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"자기 목숨 아까워서 다 같이 죽자고 했단 말이군. 이래서 용병들이란.","JPN":"自分が助かろうとしてみんなを道連れにしてしまったやつか。\\nこれだから、傭兵どもは……","ENG":"They didn’t want to die alone, so they decided to take others with them. Typical mercenaries.","TWN":"死也要拖人一起下水是吧，真不愧是傭兵。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"미안하지만 아크라브 연방군 소행이었어.","JPN":"悪いが、アクラブ連邦軍の仕業だった。","ENG":"Well, they were actually from the Acrab Federal Army.","TWN":"不好意思喔，那可是艾可拉夫聯邦軍幹的好事！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……말만 군인이지 용병이나 다름 없는 놈들 말이군.","JPN":"……軍人とは名ばかりで、実際は傭兵に等しい奴らのことか。","ENG":"... You mean the ones who call themselves soldiers, but are really no better than mercenaries.","TWN":"……他們只是號稱是軍人，實際上作為和傭兵沒兩樣！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"아, 그렇지. 그렇고 말고.","JPN":"はいはい、そうでしょうね。","ENG":"Yeah, yeah. Whatever you say.","TWN":"好好好，你說的都對。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"아무튼 의뢰인께서 예상치 못한 일이 벌어진 건 확실한 것 같군. 뭔진 몰라도 조심해야겠어.","JPN":"とにかく依頼主さんが予想できなかったことが起きたのは確かなようだな。\\n何かはわからないが、気を付けなければ。","ENG":"One thing I know for sure is that something even you didn’t expect came up. We’ll have to be careful.","TWN":"總之委託人似乎做出意料之外的事，我還是小心駛得萬年船！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"어째 날 못 믿겠다는 말처럼 들리는데, 메이슨 씨.","JPN":"どうも俺が頼りにならないというような言い草だな。メイソンさん。","ENG":"It sounds like you don’t trust me, Mr. Mason.","TWN":"梅森，你這話聽起來似乎是信不過我？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그 쪽은 초공간 돌파를 맨몸으로 버티는 괴물인지 몰라도 난 아냐.","JPN":"そっちは超空間突破に耐えられる化け物かもしれないが、俺は違う。","ENG":"You may be a monster who can withstand a hyperspace jump without any protection, but I’m not.","TWN":"拜託，可以肉身撐住超空間突破的怪物，是你又不是我。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그러니 내 몸은 내가 챙겨야지.","JPN":"だから、俺のことは俺自身で守らないと。","ENG":"I have to take care of myself.","TWN":"我當然要顧好我自己！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"우선은 정찰이 먼저야. 제인 킬러가 좋은 소식을 물어다 주길 바라자고.","JPN":"まずは偵察が先だ。ジェーン・キラーが良い知らせを運んでくれることを祈ろう。","ENG":"Well, let’s scout the area first. I hope Jane Killer gets us some good news.","TWN":"現在第一個要做的就是偵察，希望珍妮殺手可以帶回好消息。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……드론 이름이 좀 바뀐 것 같은데?","JPN":"……ドローンの名前、変わってないか？","ENG":"Did you change the drone’s name?","TWN":"……你的無人機改名字啦？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"시끄러워.","JPN":"うるせえ。","ENG":"Shut up.","TWN":"不關你的事。"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"상공에서 찍은 영상을 분석해 보면…… ","JPN":"上空から撮った映像を分析してみると……","ENG":"According to the aerial picture...","TWN":"分析從空中拍回的影片…… "},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"표정이 왜 그래, 메이슨 씨? 못 볼 꼴이라도 본 사람처럼?","JPN":"どうした、メイソンさん。何か見ちゃいけないものでも見たような顔だが……","ENG":"What's wrong, Mr. Mason? You look like you’ve seen a ghost.","TWN":"你的表情是怎麼回事？一副看到不該看的樣子？"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……이거 큰일인데.","JPN":"……これは大変だ。","ENG":"We have a problem.","TWN":"……不好了！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"스캐빈저 놈들이야.","JPN":"スカベンジャーの奴らだよ。","ENG":"The Scavengers.","TWN":"是清道夫那些傢伙！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};